#!/usr/bin/env node
/*
 * Reads R2_APP_USERNAME / R2_APP_PASSWORD (plaintext) from process.env and
 * emits electron/r2-defaults.generated.cjs with the values baked in.
 *
 * Lets a packaged build sync against the R2 gateway on first launch without
 * requiring the user to enter the worker password in the onboarding gate.
 * Stored settings in `settings.json` still take precedence at runtime (see
 * `electron/config.cjs:buildChildEnv`).
 *
 * Soft-fails if either var is missing: the generated file exports `null`
 * values and the runtime falls back to the existing onboarding flow.
 *
 * The output file is gitignored.
 */

"use strict";

const fs = require("node:fs");
const path = require("node:path");

const OUT_PATH = path.join(__dirname, "..", "electron", "r2-defaults.generated.cjs");

// Single source of truth: the R2 Worker Basic-Auth password is the same as
// EDITOR_PASSWORD (the local editor-login secret). R2_APP_PASSWORD can still
// override for split-credential setups, but the default flow is unified.
const user = (process.env.R2_APP_USERNAME || "v1editor").trim() || null;
const pass = (
  process.env.R2_APP_PASSWORD ||
  process.env.EDITOR_PASSWORD ||
  ""
).trim() || null;

const body =
  "// AUTO-GENERATED by scripts/emit-r2-defaults.cjs. Do not edit.\n" +
  '"use strict";\n' +
  `module.exports = { username: ${JSON.stringify(user)}, password: ${JSON.stringify(pass)} };\n`;

fs.mkdirSync(path.dirname(OUT_PATH), { recursive: true });
fs.writeFileSync(OUT_PATH, body, "utf8");
process.stdout.write(
  `emit-r2-defaults: wrote r2-defaults.generated.cjs (username=${user ? "set" : "unset"}, password=${pass ? "set" : "unset"})\n`,
);
